__global__ void nw_block_kernel(int *input_itemsets, int *referrence, int max_rows, int max_cols, int penalty,
    int blk, int b_index_x, int b_index_y)
{
    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int idy = blockIdx.y * blockDim.y + threadIdx.y;

    if (idx < BLOCK_SIZE && idy < BLOCK_SIZE) {
        reference_l[idy * BLOCK_SIZE + idx] = referrence[max_cols * (b_index_y * BLOCK_SIZE + idy + 1) + b_index_x * BLOCK_SIZE + idx + 1];
    }

    if (idx < BLOCK_SIZE + 1 && idy < BLOCK_SIZE + 1) {
        input_itemsets_l[idy * (BLOCK_SIZE + 1) + idx] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + idy) + b_index_x * BLOCK_SIZE + idx];
    }

    __syncthreads();

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    if (idx < BLOCK_SIZE && idy < BLOCK_SIZE) {
        input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + idy + 1) + b_index_x * BLOCK_SIZE + idx + 1] = 
            input_itemsets_l[(idy + 1) * (BLOCK_SIZE + 1) + idx + 1];
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
    int max_rows, int max_cols, int penalty)
{
    int *d_input_itemsets, *d_referrence;
    int transfer_size = max_rows * max_cols * sizeof(int);

    cudaMalloc(&d_input_itemsets, transfer_size);
    cudaMalloc(&d_referrence, transfer_size);

    cudaMemcpy(d_input_itemsets, input_itemsets, transfer_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, transfer_size, cudaMemcpyHostToDevice);

    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid(1, 1);

    printf("Processing top-left matrix\n");

    for (int blk = 1; blk <= (max_cols - 1) / BLOCK_SIZE; blk++) {
        for (int b_index_x = 0; b_index_x < blk; ++b_index_x) {
            int b_index_y = blk - 1 - b_index_x;
            nw_block_kernel<<<grid, block>>>(d_input_itemsets, d_referrence, max_rows, max_cols, penalty, blk, b_index_x, b_index_y);
            cudaDeviceSynchronize();
        }
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= (max_cols - 1) / BLOCK_SIZE; blk++) {
        for (int b_index_x = blk - 1; b_index_x < (max_cols - 1) / BLOCK_SIZE; ++b_index_x) {
            int b_index_y = (max_cols - 1) / BLOCK_SIZE + blk - 2 - b_index_x;
            nw_block_kernel<<<grid, block>>>(d_input_itemsets, d_referrence, max_rows, max_cols, penalty, blk, b_index_x, b_index_y);
            cudaDeviceSynchronize();
        }
    }

    cudaMemcpy(input_itemsets, d_input_itemsets, transfer_size, cudaMemcpyDeviceToHost);

    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

